// Package db provides database access and type mapping utilities.
//
// The dao package (generated by sqlc) uses pgtype.Timestamptz and nullable
// pointers. The domain package uses time.Time and plain strings. These helpers
// bridge the gap so handlers can use sqlc-generated queries while templates
// continue to work with domain types.
package db

import (
	"time"

	"github.com/jackc/pgx/v5/pgtype"
)

// PgTime converts a pgtype.Timestamptz to time.Time.
// Returns zero time if not valid.
func PgTime(t pgtype.Timestamptz) time.Time {
	if t.Valid {
		return t.Time
	}
	return time.Time{}
}

// TimePg converts a time.Time to pgtype.Timestamptz.
func TimePg(t time.Time) pgtype.Timestamptz {
	return pgtype.Timestamptz{Time: t, Valid: !t.IsZero()}
}

// Deref returns the string value of a *string, or "" if nil.
func Deref(s *string) string {
	if s == nil {
		return ""
	}
	return *s
}

// Ref returns a pointer to the string, or nil if empty.
func Ref(s string) *string {
	if s == "" {
		return nil
	}
	return &s
}
